                if dp[cnt][s] == INF:
                    continue
                cost = dp[cnt][s]
                for c in range(2):
                    ch = str(c)
                    change_cost = 0 if a[i] == ch else 1
                    ns = s
                    while ns > 0 and (ns == m or b[ns] != ch):
                        ns = fail[ns]
                    if ns < m and b[ns] == ch:
                        ns += 1
                    new_cnt = cnt
                    if ns == m:
                        new_cnt += 1
                        ns = fail[m]
